import { improveFlow } from "./improve.js";
import { renderMarkdown } from "./render.js";
import { setupFlow } from "./setup.js";
import { TARGETS } from "./targets.js";
import { updateFlow } from "./update.js";
export { improveFlow } from "./improve.js";
export { describeFlow, renderMermaid } from "./mermaid.js";
export { applyMustacheSections, renderMarkdown } from "./render.js";
export { computeModesPerStep, Flow, nextRefsForMode, } from "./schema.js";
export { setupFlow } from "./setup.js";
export { SHARED_VARIABLES } from "./sharedVariables.js";
export { TARGETS } from "./targets.js";
export { updateFlow } from "./update.js";
/**
 * Every flow that should be rendered into per-target plugin skill files at
 * build time. Add new flows here as they are migrated from hand-written
 * markdown to the schema-driven representation.
 */
export const ALL_FLOWS = {
    update: updateFlow,
    setup: setupFlow,
    improve: improveFlow,
};
/**
 * Output paths (relative to the monorepo root) for each (flow, target) pair.
 * The build-skills script writes here.
 *
 * If a flow shouldn't be rendered for a target, omit it from the inner map.
 */
export const FLOW_OUTPUT_PATHS = {
    update: {
        claude: "bitfab-claude-plugin/commands/update.md",
        cursor: "bitfab-cursor-plugin/skills/bitfab-update/SKILL.md",
        codex: "bitfab-codex-plugin/skills/update/SKILL.md",
    },
    setup: {
        claude: "bitfab-claude-plugin/commands/setup.md",
        cursor: "bitfab-cursor-plugin/skills/bitfab-setup/SKILL.md",
        codex: "bitfab-codex-plugin/skills/setup/SKILL.md",
    },
    improve: {
        claude: "bitfab-claude-plugin/commands/improve.md",
        cursor: "bitfab-cursor-plugin/skills/bitfab-improve/SKILL.md",
        codex: "bitfab-codex-plugin/skills/improve/SKILL.md",
    },
};
/**
 * Produce every (flow, target) rendering as in-memory strings. Used by both
 * the write script and the check-only script so they share rendering logic.
 */
export function renderAllSkills() {
    const out = [];
    for (const [flowId, flow] of Object.entries(ALL_FLOWS)) {
        const paths = FLOW_OUTPUT_PATHS[flowId] ?? {};
        for (const [targetName, outputPath] of Object.entries(paths)) {
            const target = TARGETS[targetName];
            out.push({
                flowId,
                target: targetName,
                outputPath,
                content: renderMarkdown(flow, target),
            });
        }
    }
    return out;
}
